function PlayerCard({ player }) {
  return (
    <div className="card player-card">
      <h4>{player.name}</h4>
      <p><strong>Team:</strong> {player.team}</p>
      <p className="player-role"><strong>Role:</strong> {player.role}</p>
      <div className="stats" style={{ marginTop: 10, padding: '5px 0', borderTop: '1px solid #eee' }}>
        <span>Runs: <strong>{player.runs}</strong></span> | 
        <span style={{ marginLeft: 10 }}>Wickets: <strong>{player.wickets}</strong></span>
      </div>
    </div>
  );
}

export default PlayerCard;
